class SignupService {
  private smtp = new SmtpMailer();

  register(user: User): void {
    this.saveUser(user);
    this.smtp.send({
      to: user.email,
      subject: 'Welcome',
      body: 'Thanks for joining!'
    });
  }
}

class SalesReportUseCase {
  run(range: DateRange): Report {
    const dbUrl = process.env.DB_URL ?? '';
    const db = new PostgresClient(dbUrl);
    const rows = db.query('select * from sales where day between $1 and $2', [range.from, range.to]);
    return this.toReport(rows);
  }

  private toReport(rows: unknown[]): Report { return { total: rows.length }; }
}

